#include "../cvm_state.h"
#include "../continue.h"
#include "../block.h"
__declspec(dllexport) void run(void) { CvmState*s=cvm_state(); H rec_h,o; cvm_pop(rec_h); u32 len=0,rlen=0,off=0,idx=0,end=0; u8*d=s?block_read(s->view_hash,&len):0; u8*r=block_read(rec_h,&rlen); cvm_zero(o); u64 target=s?s->view_index:0; if(s&&d&&r){while(off+36<=len){int z=1;for(int i=0;i<32;i++)if(d[off+i]){z=0;break;}if(z)break;u32 sp=(u32)d[off+32]|((u32)d[off+33]<<8)|((u32)d[off+34]<<16)|((u32)d[off+35]<<24);if(sp<4||off+32+sp>len)break;end=off+32+sp;if(idx==target)break;off=end;idx++;}if(idx==target&&end>off){u32 out_len=len-(end-off)+rlen;u8*b=malloc(out_len+1);if(b){memcpy(b,d,off);memcpy(b+off,r,rlen);memcpy(b+off+rlen,d+end,len-end);block_write(b,out_len,o);memcpy(s->view_hash,o,32);free(b);}}} if(d)free(d); if(r)free(r); cvm_push(o); cnext(); }
